import React from 'react';
import { ShoppingCart } from './ShoppingCart';
import './styles.css';

const products = [
  { id: 'p1', name: 'Wireless Headphones', price: 79.99 },
  { id: 'p2', name: 'USB-C Cable', price: 12.99 },
  { id: 'p3', name: 'Laptop Stand', price: 49.99 },
];

export default function App() {
  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Shopping Cart</h1>
      <ShoppingCart products={products} />
    </div>
  );
}

import React, { useReducer, useMemo } from 'react';
import './styles.css';

// --- Types ---
export interface Product {
  id: string;
  name: string;
  price: number;
}

export interface CartItem extends Product {
  quantity: number;
}

type CartAction =
  | { type: 'ADD_ITEM'; product: Product }
  | { type: 'REMOVE_ITEM'; id: string }
  | { type: 'UPDATE_QUANTITY'; id: string; quantity: number }
  | { type: 'CLEAR_CART' };

// --- Reducer ---
// TODO: Implement the cartReducer function
export function cartReducer(state: CartItem[], action: CartAction): CartItem[] {
  switch (action.type) {
    case 'ADD_ITEM':
      // TODO: Add product or increment quantity
      return state;
    case 'REMOVE_ITEM':
      // TODO: Remove item by id
      return state;
    case 'UPDATE_QUANTITY':
      // TODO: Update quantity; remove if ≤ 0
      return state;
    case 'CLEAR_CART':
      // TODO: Return empty array
      return state;
    default:
      return state;
  }
}

// --- Component ---
interface ShoppingCartProps {
  products: Product[];
}

export const ShoppingCart: React.FC<ShoppingCartProps> = ({ products }) => {
  const [cart, dispatch] = useReducer(cartReducer, []);

  const totalItems = useMemo(
    () => cart.reduce((sum, item) => sum + item.quantity, 0),
    [cart]
  );
  const totalPrice = useMemo(
    () => cart.reduce((sum, item) => sum + item.price * item.quantity, 0),
    [cart]
  );

  return (
    <div className="cart-layout">
      <div className="cart-products">
        <h2>Products</h2>
        {products.map(p => (
          <div key={p.id} className="cart-product">
            <span>{p.name} — ${p.price.toFixed(2)}</span>
            <button data-testid={`add-${p.id}`} onClick={() => dispatch({ type: 'ADD_ITEM', product: p })}>
              Add to Cart
            </button>
          </div>
        ))}
      </div>
      <div className="cart-summary">
        <h2>Cart</h2>
        {cart.length === 0 && <p className="cart-empty">Your cart is empty.</p>}
        {cart.map(item => (
          <div key={item.id} className="cart-item">
            <span>{item.name}</span>
            <div className="cart-item__controls">
              <button data-testid={`decrease-${item.id}`} onClick={() => dispatch({ type: 'UPDATE_QUANTITY', id: item.id, quantity: item.quantity - 1 })}>−</button>
              <span data-testid={`qty-${item.id}`}>{item.quantity}</span>
              <button data-testid={`increase-${item.id}`} onClick={() => dispatch({ type: 'UPDATE_QUANTITY', id: item.id, quantity: item.quantity + 1 })}>+</button>
              <button data-testid={`remove-${item.id}`} onClick={() => dispatch({ type: 'REMOVE_ITEM', id: item.id })}>✕</button>
            </div>
          </div>
        ))}
        <div className="cart-totals">
          <span>Items: <strong data-testid="total-items">{totalItems}</strong></span>
          <span>Total: <strong data-testid="total-price">${totalPrice.toFixed(2)}</strong></span>
        </div>
        <button data-testid="clear-cart" onClick={() => dispatch({ type: 'CLEAR_CART' })} disabled={cart.length === 0}>
          Clear Cart
        </button>
      </div>
    </div>
  );
};

.cart-layout {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 2rem;
}

.cart-products h2,
.cart-summary h2 {
  margin: 0 0 1rem;
  font-size: 1.125rem;
}

.cart-product {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 0.75rem 0;
  border-bottom: 1px solid #f3f4f6;
}

.cart-product button {
  padding: 0.375rem 0.75rem;
  border: 1px solid #3b82f6;
  background: #eff6ff;
  color: #3b82f6;
  border-radius: 0.25rem;
  cursor: pointer;
  font-size: 0.8125rem;
}

.cart-empty {
  color: #9ca3af;
  font-style: italic;
}

.cart-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 0.5rem 0;
  border-bottom: 1px solid #f3f4f6;
}

.cart-item__controls {
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.cart-item__controls button {
  width: 1.5rem;
  height: 1.5rem;
  border: 1px solid #d1d5db;
  background: #f9fafb;
  border-radius: 0.25rem;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 0.75rem;
}

.cart-totals {
  display: flex;
  justify-content: space-between;
  margin-top: 1rem;
  padding-top: 0.75rem;
  border-top: 2px solid #e5e7eb;
  font-size: 0.9375rem;
}

.cart-summary > button:last-child {
  margin-top: 0.75rem;
  width: 100%;
  padding: 0.5rem;
  border: 1px solid #ef4444;
  background: #fef2f2;
  color: #ef4444;
  border-radius: 0.375rem;
  cursor: pointer;
}

.cart-summary > button:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

