import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import { cartReducer } from './ShoppingCart';

// Direct reducer tests
const p1 = { id: 'p1', name: 'A', price: 10 };
const p2 = { id: 'p2', name: 'B', price: 20 };

describe('cartReducer', () => {
  it('adds a new item with quantity 1', () => {
    const result = cartReducer([], { type: 'ADD_ITEM', product: p1 });
    expect(result).toHaveLength(1);
    expect(result[0]).toEqual({ ...p1, quantity: 1 });
  });

  it('increments quantity for existing item', () => {
    const state = [{ ...p1, quantity: 2 }];
    const result = cartReducer(state, { type: 'ADD_ITEM', product: p1 });
    expect(result[0].quantity).toBe(3);
  });

  it('removes an item by id', () => {
    const state = [{ ...p1, quantity: 1 }, { ...p2, quantity: 1 }];
    const result = cartReducer(state, { type: 'REMOVE_ITEM', id: 'p1' });
    expect(result).toHaveLength(1);
    expect(result[0].id).toBe('p2');
  });

  it('updates quantity', () => {
    const state = [{ ...p1, quantity: 2 }];
    const result = cartReducer(state, { type: 'UPDATE_QUANTITY', id: 'p1', quantity: 5 });
    expect(result[0].quantity).toBe(5);
  });

  it('removes item when quantity is set to 0', () => {
    const state = [{ ...p1, quantity: 1 }];
    const result = cartReducer(state, { type: 'UPDATE_QUANTITY', id: 'p1', quantity: 0 });
    expect(result).toHaveLength(0);
  });

  it('clears the cart', () => {
    const state = [{ ...p1, quantity: 2 }, { ...p2, quantity: 3 }];
    const result = cartReducer(state, { type: 'CLEAR_CART' });
    expect(result).toHaveLength(0);
  });

  it('does not mutate original state', () => {
    const state = [{ ...p1, quantity: 1 }];
    const frozen = Object.freeze(state.map(i => Object.freeze(i)));
    expect(() => cartReducer(frozen as any, { type: 'ADD_ITEM', product: p2 })).not.toThrow();
  });
});

